import React, { useState } from 'react';
import './Home.css'; // Используем общие стили или создай Vacancy.css

function Vacancy() {
  const [file, setFile] = useState(null);
  const [resultImage, setResultImage] = useState(null);

  const handleUpload = (e) => {
    e.preventDefault();
    if (!file) return alert("Загрузи фото!");
    
    // Имитация "ИИ Семисвинофф"
    setResultImage("https://img.freepik.com/free-photo/view-of-funny-pig-looking-curious_23-2150754884.jpg");
  };

  return (
    <div style={{ padding: '50px', textAlign: 'center' }}>
      <div className="card" style={{ maxWidth: '500px', margin: '0 auto', background: 'white', padding: '20px', borderRadius: '15px' }}>
        <h2 style={{ color: 'red' }}>Тест на должность в Семисвинофф</h2>
        {!resultImage ? (
          <form onSubmit={handleUpload}>
            <p>Загрузите ваше фото для анализа нейросетью</p>
            <input type="file" onChange={(e) => setFile(e.target.files[0])} />
            <br /><br />
            <button type="submit" className="nav-link" style={{ background: 'red', color: 'white', border: 'none', cursor: 'pointer' }}>
                Проверить совместимость
            </button>
          </form>
        ) : (
          <div>
            <h3>РЕЗУЛЬТАТ: ВЫ ПОДХОДИТЕ!</h3>
            <img src={resultImage} alt="Свинья" style={{ width: '100%', borderRadius: '10px' }} />
            <br />
            <a href={resultImage} download="My_Job_Pass.jpg" style={{ color: 'blue', fontWeight: 'bold' }}>
               Скачать рабочий пропуск (.JPG)
            </a>
            <br /><br />
            <button onClick={() => setResultImage(null)}>Начать заново</button>
          </div>
        )}
      </div>
    </div>
  );
}

export default Vacancy;
